
// load-balancer.js — Auto-generated by SeekCode Optimizer
class IntelligentLoadBalancer {
  constructor(workers = 3) {
    this.workers = Array(workers).fill().map((_, i) => ({
      id: i,
      busy: false,
      tasks: 0,
      lastTaskTime: 0,
      errorCount: 0
    }));
    this.queue = [];
    this.metrics = { totalTasks: 0, avgWaitTime: 0 };
  }

  async execute(task) {
    const startTime = Date.now();
    const worker = this.getBestWorker();
    
    if (!worker) {
      // Wait for available worker
      return new Promise(resolve => {
        this.queue.push({ task, resolve, startTime });
      });
    }
    
    return this.runTask(worker, task, startTime);
  }

  getBestWorker() {
    // Find worker with fewest tasks and lowest error rate
    return this.workers
      .filter(w => !w.busy)
      .sort((a, b) => a.tasks - b.tasks || a.errorCount - b.errorCount)[0];
  }

  async runTask(worker, task, startTime) {
    worker.busy = true;
    worker.tasks++;
    worker.lastTaskTime = Date.now();
    
    try {
      const result = await task();
      const duration = Date.now() - startTime;
      this.updateMetrics(duration);
      return result;
    } catch (err) {
      worker.errorCount++;
      throw err;
    } finally {
      worker.busy = false;
      this.processQueue();
    }
  }

  processQueue() {
    if (this.queue.length > 0) {
      const next = this.queue.shift();
      this.runTask(this.getBestWorker(), next.task, next.startTime)
        .then(next.resolve);
    }
  }

  updateMetrics(duration) {
    this.metrics.totalTasks++;
    this.metrics.avgWaitTime = (this.metrics.avgWaitTime * (this.metrics.totalTasks - 1) + duration) / this.metrics.totalTasks;
  }

  getStats() {
    return {
      workers: this.workers.map(w => ({
        id: w.id,
        tasks: w.tasks,
        errorRate: w.errorCount / Math.max(1, w.tasks),
        idle: !w.busy
      })),
      queueLength: this.queue.length,
      metrics: this.metrics
    };
  }
}

module.exports = { IntelligentLoadBalancer };
